lemma MulLeMonotone(c: int, a: int, b: int)
  requires c > 0
  requires a <= b
  ensures c * a <= c * b
  decreases c
{
  if c > 1 {
    MulLeMonotone(c - 1, a, b);
  }
}

lemma GcdBound(a: int, b: int)
  requires 0 < a < b
  ensures Gcd(a, b) * 2 <= b
  decreases b, a
{
  assert a % b == a;
  assert Gcd(a, b) == Gcd(b, a);

  var r := b % a;
  if r == 0 {
    assert Gcd(b, a) == a;
    var k := b / a;
    assert b == a * k;
    assert k >= 2;
    assert a <= b / 2;  // Prove a is at most half of b
    MulLeMonotone(a, 2, k);
  } else {
    assert 0 < r && r < a;
    assert Gcd(b, a) == Gcd(a, r);
    assert r % a == r;
    assert Gcd(r, a) == Gcd(a, r);
    GcdBound(r, a);
    assert Gcd(a, b) * 2 <= a;  // Recursive call ensures this
    assert a < b;
    assert Gcd(a, b) * 2 <= b;  // Since a < b
  }
}

